const items = [];

for (const item of $input.all()) {
  const email = item.json.Email;
  const name = item.json.Name || 'Valued Customer';
  const company = item.json.Company || '';

  // Персонализация темы письма
  const subject = `Специальное предложение для ${company || name}`;

  // Персонализация тела письма
  const body = `
    <html>
      <head>
        <style>
          body { font-family: Arial, sans-serif; line-height: 1.6; color: #333; }
          .container { max-width: 600px; margin: 0 auto; padding: 20px; }
          .header { background-color: #4CAF50; color: white; padding: 20px; text-align: center; }
          .content { padding: 20px; background-color: #f9f9f9; }
          .button { display: inline-block; padding: 10px 20px; background-color: #4CAF50; color: white; text-decoration: none; border-radius: 5px; margin-top: 20px; }
          .footer { text-align: center; padding: 20px; font-size: 12px; color: #666; }
        </style>
      </head>
      <body>
        <div class="container">
          <div class="header">
            <h1>Здравствуйте, ${name}!</h1>
          </div>
          <div class="content">
            <p>Мы рады представить вам наше специальное предложение${company ? ' для ' + company : ''}.</p>
            <p>В рамках нашей новой кампании мы предлагаем:</p>
            <ul>
              <li>Скидка 20% на все услуги</li>
              <li>Бесплатная консультация</li>
              <li>Приоритетная поддержка</li>
            </ul>
            <p>Это предложение действительно только до конца месяца!</p>
            <a href="https://example.com/offer?email=${encodeURIComponent(email)}" class="button">Узнать больше</a>
          </div>
          <div class="footer">
            <p>Если вы хотите отписаться от рассылки, <a href="https://example.com/unsubscribe?email=${encodeURIComponent(email)}">нажмите здесь</a></p>
            <p>&copy; 2026 Ваша Компания. Все права защищены.</p>
          </div>
        </div>
      </body>
    </html>
  `;

  items.push({
    json: {
      email: email,
      name: name,
      company: company,
      subject: subject,
      body: body,
      originalData: item.json
    }
  });
}

return items;

// Логирование успешной отправки
const timestamp = new Date().toISOString();
const email = $json.email;
const name = $json.name;

return {
  json: {
    timestamp: timestamp,
    email: email,
    name: name,
    status: 'sent',
    message: `Email successfully sent to ${name} (${email})`
  }
};

// Обработка ошибки отправки
const timestamp = new Date().toISOString();
const email = $json.email || 'unknown';
const error = $json.error || 'Unknown error';

return {
  json: {
    timestamp: timestamp,
    email: email,
    status: 'failed',
    error: error,
    message: `Failed to send email to ${email}: ${error}`
  }
};

// Сводная статистика по рассылке
const allItems = $input.all();
const totalSent = allItems.filter(item => item.json.status === 'sent').length;
const totalFailed = allItems.filter(item => item.json.status === 'failed').length;
const totalProcessed = totalSent + totalFailed;

const summary = {
  campaignDate: new Date().toISOString(),
  totalProcessed: totalProcessed,
  successfullySent: totalSent,
  failed: totalFailed,
  successRate: totalProcessed > 0 ? ((totalSent / totalProcessed) * 100).toFixed(2) + '%' : '0%'
};

return {
  json: summary
};
